import{_ as a,o as i,c as e,ae as s}from"./chunks/framework.RRduUuAx.js";const c=JSON.parse('{"title":"External Installation - Method 2 (manual partitioning)","description":"","frontmatter":{"prev":{"text":"Go back to Installation Methods","link":"/installation"},"next":{"text":"Ending","link":"/ending"}},"headers":[],"relativePath":"ps4/external-installation-manual.md","filePath":"ps4/external-installation-manual.md","lastUpdated":1777870860000}'),n={name:"ps4/external-installation-manual.md"};function o(l,t,r,d,p,h){return i(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="external-installation-method-2-manual-partitioning" tabindex="-1">External Installation - Method 2 (manual partitioning) <a class="header-anchor" href="#external-installation-method-2-manual-partitioning" aria-label="Permalink to &quot;External Installation - Method 2 (manual partitioning)&quot;">​</a></h1><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Remember we&#39;ll format the external drive! Back up any existing data you care about.</p></div><p>This method involves manual partitioning. It&#39;s slower to do, but works flawlessly, therefore it&#39;s recommended if you have issues.</p><p>Get a Linux PC or VM (even a Live ISO works), or any program that can format drives in Linux&#39;s formats.</p><p>Then, plug in your drive, and use &quot;GParted&quot;, &quot;KDE Partition Manager&quot;, or &quot;Aoemi Partition Assistant&quot; on Windows to format your external drive like so:</p><ul><li>50MB of FAT32 at the start of the drive <u>with an empty label</u></li><li>And a partition of the remaining space formatted as EXT4 <u>labeled &quot;psxitarch&quot;</u><ul><li>BTRFS works too, but EXT4 is faster and recommended</li></ul></li></ul><p>Now move your bzImage (and bootargs if you need it) and initramfs to the FAT32 partition.</p><p>Then, you will need to untar your distro of choice at the root of the bigger EXT4 partition, using this command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -xvJpf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps4linux.tar.xz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /run/media/YOURNAME/psxitarch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --numeric-owner</span></span></code></pre></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Replace <code>YOURNAME</code> and <code>ps4linux.tar.xz</code> accordingly. Also, you need to check that the drive is actually called psxitarch, it&#39;ll be different if you didn&#39;t set it.</p></div><h2 id="booting-up" tabindex="-1">Booting up <a class="header-anchor" href="#booting-up" aria-label="Permalink to &quot;Booting up&quot;">​</a></h2><p>Now that the storage is covered, it should already boot into the desktop. If it doesn&#39;t, and instead shows a Rescue Shell command prompt, type this until the distro starts:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resume-boot</span></span></code></pre></div><details class="details custom-block"><summary>If it doesn&#39;t work check this!</summary><p>If for some reason it doesn&#39;t work for you, run the following commands (thanks @gryoza on Discord and @bene4k on Reddit for this):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sdb2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /newroot</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chroot</span></span></code></pre></div><p>You may need to do this at every reboot.</p></details>`,14)])])}const k=a(n,[["render",o]]);export{c as __pageData,k as default};
